import { afterEach, describe, expect, it } from "vitest";
import { resolveCodingAgentDisplayName } from "./resolveCodingAgentDisplayName.js";
describe("resolveCodingAgentDisplayName", () => {
    const env = { ...process.env };
    afterEach(() => {
        process.env = { ...env };
    });
    it("uses BITFAB_AGENT_LABEL when set", () => {
        process.env.BITFAB_AGENT_LABEL = "  My Agent ";
        delete process.env.CODEX_THREAD_ID;
        delete process.env.CODEX_CI;
        delete process.env.CODEX_SANDBOX;
        delete process.env.CLAUDE_CODE_VERSION;
        expect(resolveCodingAgentDisplayName()).toBe("My Agent");
    });
    it("prefers Codex when CODEX_THREAD_ID is set", () => {
        delete process.env.BITFAB_AGENT_LABEL;
        process.env.CODEX_THREAD_ID = "t1";
        delete process.env.CLAUDE_CODE_VERSION;
        expect(resolveCodingAgentDisplayName()).toBe("Codex");
    });
    it("detects Claude via CLAUDE_CODE_VERSION", () => {
        delete process.env.BITFAB_AGENT_LABEL;
        delete process.env.CODEX_THREAD_ID;
        delete process.env.CODEX_CI;
        delete process.env.CODEX_SANDBOX;
        process.env.CLAUDE_CODE_VERSION = "1.0.0";
        delete process.env.CURSOR_PLUGIN_ROOT;
        expect(resolveCodingAgentDisplayName()).toBe("Claude");
    });
    it("detects Cursor via CURSOR_PLUGIN_ROOT", () => {
        delete process.env.BITFAB_AGENT_LABEL;
        delete process.env.CODEX_THREAD_ID;
        delete process.env.CODEX_CI;
        delete process.env.CODEX_SANDBOX;
        delete process.env.CLAUDE_CODE_VERSION;
        process.env.CURSOR_PLUGIN_ROOT = "/some/path";
        expect(resolveCodingAgentDisplayName()).toBe("Cursor");
    });
    it("falls back to Coding agent when no signals", () => {
        delete process.env.BITFAB_AGENT_LABEL;
        delete process.env.CODEX_THREAD_ID;
        delete process.env.CODEX_CI;
        delete process.env.CODEX_SANDBOX;
        delete process.env.CLAUDE_CODE_VERSION;
        delete process.env.CURSOR_PLUGIN_ROOT;
        expect(resolveCodingAgentDisplayName()).toBe("Coding agent");
    });
});
